const Q_CHEMISTRY_2024_MODEL_II=[{"id": "objective>Chemistry>2024-Model-II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When steam is passed over red hot coke, what is produced?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen oxygen and carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen and carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen and carbon (II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen and trioxocarbonate (IV) acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When steam is passed over red-hot coke, water gas is formed which consists of carbon monoxide and hydrogen. <br/> C + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O→CO + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2024-Model-II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The exhaust fumes from a garage in a place that uses petrol of high sulphur content are bound to contain?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO and SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO and HCl</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The exhaust fumes from a garage that uses petrol with high sulphur content are bound to contain Carbon Monoxide (CO) and Sulphur Dioxide (SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). This is because when fuels containing sulphur are burned, sulphur compounds in the fuel are oxidised to sulphur dioxide, while carbon compounds are oxidized to carbon monoxide</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : SULPHUR"}, {"id": "objective>Chemistry>2024-Model-II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following sulphide salts forms white crystals except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaS</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S is yellow. Actually, Ammonium Sulfide ((NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S) is typically a yellowish solid at low temperatures, but it's unstable above -18 °C. It has a very strong and highly unpleasant smell of rotten eggs</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : SULPHUR"}, {"id": "objective>Chemistry>2024-Model-II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When chlorine is passed into water and subsequently exposed to sunlight, the gas evolved is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HOCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When chlorine is passed into water and subsequently exposed to sunlight, the gas evolved is Oxygen (O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). When chlorine gas dissolves in water, it forms chlorine water, which includes hydrochloric acid and emits oxygen gas when exposed to light.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2024-Model-II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of synthetic polymer is shown in the image? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">polystyrene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">teflon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polypropylene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polyethylene</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polystyrene is a hard, brilliantly transparent, stiff resin. It is produced by the polymerization of styrene and is the most widely used plastic. At room temperature, the thermoplastic polymer is a solid but when heated above 100 °C it flows. It becomes rigid again when it cools down. Polystyrene is insoluble in water.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2024-Model-II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia gas is normally dried with?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">concentrated sulphuric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quicklime</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anhydrous calcium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium sulphate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia gas is normally dried with Calcium Oxide (CaO), also known as Quick Lime. This is because Ammonia gas (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) contains water vapor, and to remove this water vapor, the gas is passed through a drying tower that contains Calcium Oxide. The Calcium Oxide absorbs the water content, and pure Ammonia gas is obtained</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2024-Model-II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used as an 'anti-knock' in automobile engines? automobile engines?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tetramethyl silane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lead tetra-ethyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glycerol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n-heptane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An 'anti-knock' agent is a gasoline additive used to reduce engine knocking and increase the fuel's octane rating. It works by raising the temperature and pressure at which auto-ignition occurs. Here are some typical agents that have been used for their anti-knock properties: <br/> Tetraethyllead (still in use as a high octane additive) <br/> MTBE <br/> Ethanol</div>", "topic": "HYDROCARBON"}, {"id": "objective>Chemistry>2024-Model-II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What reaction takes place when palm-oil is added to potash and foam are observed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Neutralization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saponification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Esterification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Salting-out</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When palm oil is added to potash and foam is observed, a saponification reaction is taking place. In this reaction, palm oil, which serves as the organic acid (specifically palmitic acid), reacts with potash (concentrated KOH), which serves as the base. This leads to the formation of soap, and the presence of bubbles or foam indicates the formation of soap. This is a classic example of a saponification reaction, which is fundamental to soap-making</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2024-Model-II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When ethanol is heated with excess concentrated sulphuric acid, the ethanol is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxidized to ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymerized to polyethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dehydrated to ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dehydrated to ethyne</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ethanol is heated with excess concentrated sulphuric acid, it undergoes a dehydration reaction to form ethene. This process is facilitated by the sulphuric acid, which acts as a dehydrating agent.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2024-Model-II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following chemical formulas represents an organic compound that belongs to the same homologous series as that of the hydrocarbon shown? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1-Hexene (hex-1-ene) is an organic compound with the formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>. It is an alkene</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2024-Model-II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The general formula of an alkyl halide (where X represents the halide) is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n- 2</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 1</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 2</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n</span>X</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 1</span>X. . Alkyl halides, also known as haloalkanes, are compounds in which one or more hydrogen atoms in an alkane have been replaced by halogen atoms (fluorine, chlorine, bromine, or iodine). They are a type of substituted hydrocarbon</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2024-Model-II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are made by the process of polymerization?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nylon and soap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nylon and artificial rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Soap and butane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Margarine and nylon</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of polymerization involves reacting monomer molecules together in a chemical reaction to form polymer chains or three-dimensional networks. Here are some examples of substances that are made by the process of polymerization: <br/> Plastics: These are polymers made from synthetic materials. <br/> Natural materials: Many natural materials such as proteins, cellulose, starch, and complex silicate minerals are polymers. <br/> Artificial fibers, films, plastics, semisolid resins, and rubbers: These are also polymers.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2024-Model-II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Starch can be converted to ethyl alcohol by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isomerization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cracking</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Starch can be converted to ethyl alcohol (ethanol) by a process known as fermentation. This is a biological process in which sugars such as glucose, which can be derived from starch, are converted into cellular energy, producing ethanol and carbon dioxide as by-products. <br/> The process of fermentation starts with glucose and ends with the formation of ethanol and carbon dioxide.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2024-Model-II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of liquid molecules from the surface of the liquid to the gaseous phase above it is known as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Brownian movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquefaction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of liquid molecules from the surface of the liquid to the gaseous phase above it is known as evaporation. This process, also called vaporization, generates a vapor pressure above the liquid. Molecules in the gas phase can collide with the liquid surface and reenter the liquid via condensation. It's a fundamental part of the water cycle and is constantly occurring throughout nature</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2024-Model-II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a sheet of paper is placed in the path of a radioactive source, the radiation emitted, which passes through the paper consists of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alpha and beta particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alpha particles and gamma rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beta particles and gamma rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beta particles only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a sheet of paper is placed in the path of a radioactive source, the types of radiation that can pass through the paper are beta particles and gamma rays. <br/> Beta particles are electrons that are not attached to an atom. They have a small mass and a negative charge. Beta radiation can penetrate air and paper, but it can be stopped by a thin sheet of aluminium. <br/> Gamma rays are a form of electromagnetic radiation, like X-rays, but much higher in energy and even more dangerous to living systems. Gamma radiation is the most penetrating. Even small levels can penetrate air, paper or thin metal. Unlike the other kinds of radiation, there is no mass or charge</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>2024-Model-II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given the organic compound, how would this be named? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cis-2-butene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trans-1-butene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cis-1-butene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trans-2-butene</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The isomer in which the two methyl (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) groups lie on the same side of the molecule is called the cis isomer (Latin cis, meaning \"on this side\") and is named cis-2-butene.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2024-Model-II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the relative molecular mass of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> [H=1, C=12; Na=23; O=16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">106</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180</div>", "<div style=\"font-family:Cambria;font-size:17px;\">142</div>", "<div style=\"font-family:Cambria;font-size:17px;\">286</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molar mass of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>= (23 * 2) + (12 * 1) + (16 * 3) <br/> =46+12+48=106 <br/> Molar mass of 10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O=[10(2 * 1) + 16] <br/> =10[2 + 16] <br/> =10[18] <br/> =180 <br/> Molar mass of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = 106+180=286 <br/> </div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What mass of a divalent metal M (atomic mass = 40) would react with excess hydrochloric acid to liberate 224cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> dry hydrogen gas measured at S.T.P?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.0 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4 g</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">let the divalent metal be X <br/> X + 2HCl → XCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 1mole of X liberated 1 mole of Hydrogen gas ( one mole of any gas at STP has a volume of 22400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> or 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> 40  → 22400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> ? → 224cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> mass of X = 40 * 224/22400 <br/> mass of X = 0.4g</div>", "topic": "GAS LAW"}, {"id": "objective>Chemistry>2024-Model-II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of atoms of chlorine present in 5.85g of NaCl is [Avogadro's Number = 6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">22</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.85 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.85 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mass of Cl in 5.85g NaCl = 35.5 x 5.85/58.5=3.55g <br/> n=m/M=N/N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> <br/> 3.55/35.5=N/6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> <br/> N=1/10 x 6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> <br/> N=6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">22</span></div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the name of the compound shown? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trans-2-pentene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trans-1-butene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trans-2-butene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trans-1-propene</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trans-2-Butene is a colorless gas. It is used as a solvent, as a cross-linking agent, in the polymerization of gasoline, and in butadiene synthesis. </div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2024-Model-II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How much of magnesium is required to react with 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.5 M HCl? [Mg = 24]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.3g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.4g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mg(s) + 2HCl(aq) → MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span>+ H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> 1mole of Mg react with 2moles of HCl <br/> Volume =250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.25dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Molar conc.=0.5M <br/> Therefore Amount = Molar conc. * Volume <br/> Amount = 0.5 *0.25=0.125mols <br/> 0.125mol of HCl/2 = 0.0625mol of Mg <br/> no of moles = mass / Molar mass <br/> mass= 0.0625*24 <br/> mass=1.5g</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2024-Model-II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a saturated solution of sugar (molar mass 342.0g) at 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C was evaporated to dryness, 34.2g of dry solid was obtained. The solubility of sugar at 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0 moles dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0 moles dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.5 moles dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 moles dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solubility=number of moles / volume(dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>) <br/> = 34.2/342 divided by 50/1000 <br/> 0.1 / 0.05 <br/> 2mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2024-Model-II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>AsO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>(H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span> is 38.9g per 100g H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. What is the mass percentage of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>AsO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> in the saturated solution? <br/>  <br/> (As = 75, Na = 23, O = 16, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">87.27%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">38.9%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19.1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.75%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>AsO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>(H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span> = 23 * 3 + 75 + 16 * 4 + 18 * 12=424g/mol <br/>  Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>AsO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> = 23 * 3 + 75 + 16 * 4 = 208g/mol <br/> Mass of anhydrous compound in 38.9g hydrated compound= 38.9 * 208g/mol/424g/mol=19.1g <br/> Mass of water in hydrated salt = 38.9-19.1=19.8g <br/>  Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>AsO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>=19.1g <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O =19.8 + 100=119.8g <br/> Total mass of solution = 19.1 + 119.8=138.9g <br/> Mass %  Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>AsO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> in solution =19.1g *100/138.9 <br/> =13.75% <br/>  </div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 24.83 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.15 M NaOH is titrated to its end point with 39.45 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of HCl, what is the molarity of the HCl?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.094 M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.150 M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.940 M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.500 M</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NaOH + HCl → NaCl + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O moles ratio = 1/1 <br/> Ma*Va/Mb*Vb=Na/Nb <br/>  <br/> Ma*39.45/0.15*24.83=1/1 <br/>  <br/> Ma=0.094M</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2024-Model-II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An isotope has an atomic number of 17 and a mass number of 36. Which of the following gives the correct number of neutrons and protons in an atom of the isotope?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Neutrons 53, Protons 17</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutrons 17, Protons 36</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutrons 19, Protons 17</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutrons 36, Protons 17</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mass number = number of protons + number of neutrons <br/> 36 = 17 + X; X = 36 -17 = 19 <br/> 19 neutrons and 17 protons</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following represents a correct name for the compound shown in the diagram? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,2,3-tribromobenzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,2,4-tribromobenzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,3,6-tribromobenzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tribromobenzenes are a group of bromobenzenes with the formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, consisting of three bromine atoms bonded to a central benzene ring.</div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2024-Model-II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of a 0.1 M H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will be required to neutralize 45.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a 0.2 M NaOH?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">27.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 3NaOH → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 0.1M, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> =?, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>=0.2, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> =45, n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>=1, n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>=3 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> <br/> =0.1 x V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/0.2 x 45=1/3 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 30 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2024-Model-II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One mole of propane is mixed with five moles of oxygen. The mixture is ignited and the propane burns completely. What is the volume of the products at s.t.p? <br/> (G.M.V = 22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">112.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">67.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">56.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">44.8 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span> + 5O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> One mole of a gas is = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Therefore, volume of 3 moles of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is 3×22.4= 67.2dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2024-Model-II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The forces holding naphthalene crystals together can be overcome when naphthalene is heated to a temperature of 354K resulting in the crystal to melting. These forces are known as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coulombic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Van der waals</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The forces that hold naphthalene crystals together are known as Van der Waals forces. These forces are a type of weak intermolecular force that occur between neutral molecules. Naphthalene, being a non-polar molecule, doesn't have ionic or covalent bonding between its molecules in the solid state. Instead, the molecules are held together by these weaker Van der Waals forces, which can be overcome by heating, leading to melting.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2024-Model-II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the most common way to dispose the synthetic polymer shown in the image? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It is burned.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is recycled.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is chopped up.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is buried</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most common way to dispose the synthetic polymer shown in the image is by recycling the  products.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2024-Model-II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these metals Mg, Fe, Pb and Cu will dissolve readily in dilute HCl?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">All the metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg, Fe and Cu </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg, Fe and Pb </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg and Fe only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium (Mg) and Iron (Fe) will readily dissolve in dilute Hydrochloric Acid (HCl). <br/> Magnesium reacts with hydrochloric acid to form magnesium chloride and hydrogen gas. <br/> Iron also reacts with hydrochloric acid, displacing the hydrogen from the HCl to produce iron chloride, sometimes known as ferrous chloride</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2024-Model-II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the solubility of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> at 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C, if 20.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of it's saturated solution at that temperature gave 1.75g of the anhyrous salt. [C=12, O=16, Na = 23]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.825</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.625</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.525</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.425</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />molar mass</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">1000<hr size=\"1\" />vol of solvent</td></tr></table></div> <br/> Molar mass of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>= (23 x 2 ) + 12 + (16 x 3) = 106 gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.75<hr size=\"1\" />106</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">1000<hr size=\"1\" />20</td></tr></table></div>= 0.825 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2024-Model-II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A voltmeter containing silver trioxonitrate(V) solution was connected in series to another voltmeter containing copper(II)tetraoxosulphate(VI) solution. when a current of 0.200 ampere was passed through the solution, 0.780g of silver was deposited. Calculate the mass of copper that would be deposited in the copper that would be deposited in the copper voltmeter[Cu = 63.5; Ag = 108; IF = 96500C] <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.23g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.33g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.43g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.46g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Ag <br/> 1 mole of Ag  → 1F <br/> 108g → 1x 96500 <br/> 0.780g →Q <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Q</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">0.780x9600<hr size=\"1\" />108</td></tr></table></div> <br/> Q = 696.9c <br/>  <br/> Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> →Cu <br/> 1 mole of Cu →2F <br/> 63.5g → 2 x 96500 <br/> m→ 696.9 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">63.5x696.9<hr size=\"1\" />2x96500</td></tr></table></div> <br/> m = 0.23g</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2024-Model-II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the following table <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"> Substance</td><td style=\"border:1px solid black;text-align:center;\">Melting point / <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td><td style=\"border:1px solid black;text-align:center;\">Boiling point / <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">P</td><td style=\"border:1px solid black;text-align:center;\">-78</td><td style=\"border:1px solid black;text-align:center;\">-25</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Q</td><td style=\"border:1px solid black;text-align:center;\">-8</td><td style=\"border:1px solid black;text-align:center;\">40</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">R</td><td style=\"border:1px solid black;text-align:center;\">-6</td><td style=\"border:1px solid black;text-align:center;\">150</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">S</td><td style=\"border:1px solid black;text-align:center;\">44</td><td style=\"border:1px solid black;text-align:center;\">280</td></tr></table></div>Which of the substances is a liquid at room temperature and rapidly evaporates on exposure to air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">S</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Substance Q has a melting point below room temperature and a boiling point above room temperature, which means it would be a liquid at room temperature and would evaporate when exposed to air.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2024-Model-II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On exposing palm wine to air for some days, it becomes sour owing to the conversion of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glucose to ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glucose to gluconic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol to ethanoic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol to ethanal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When palm wine is exposed to air for some days, the ethanol in it gets oxidized to ethanoic acid, making the wine sour. This is due to the action of bacteria in the air that convert ethanol to ethanoic acid in the presence of oxygen. Therefore, the correct answer is 'ethanol to ethanoic acid'.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2024-Model-II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When excess carbon (lV) oxide is passed into lime water, the turbidity produced initially disappears due to the formation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> calcium oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium carbide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium hydrogentrioxocarbonate (IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trioxocarbonate (IV) acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When excess carbon (IV) oxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) is passed into lime water (Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), it initially forms calcium carbonate (CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) which causes the turbidity. However, with excess CO2, the calcium carbonate reacts further to form calcium hydrogentrioxocarbonate (IV) (Ca(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), which is soluble in water and hence the turbidity disappears.</div>", "topic": "METALS AND THEIR COMPOUNDS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2024-Model-II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are properties of transition metals except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">variable oxidation states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tendency to form complex ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of coloured ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low melting points</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transition metals are known for their high melting points due to the strong metallic bonding caused by the delocalized 'sea' of electrons. Therefore, the statement 'low melting points' is not a property of transition metals.</div>", "topic": "METALS AND THEIR COMPOUNDS : METALS OF THE FIRST TRANSITION SERIES"}, {"id": "objective>Chemistry>2024-Model-II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following salts will produce a gas on reacting with hydrochloric acid except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">FeS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper sulfate (CuSO4) does not react with hydrochloric acid to produce a gas. The other salts listed (calcium carbonate, iron sulfide, and sodium sulfite) all react with hydrochloric acid to produce a gas.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2024-Model-II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many unpaired electrons are there in an atom of an element with the following electronic configuration? 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electronic configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> indicates that all the electrons are paired. Unpaired electrons are those that occupy an orbital alone. In this configuration, all orbitals are fully occupied, hence there are no unpaired electrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2024-Model-II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The loss of molecules of water of crystallization to the atmosphere by some crystalline salts is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efflorescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effervescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phosphorescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluorescence</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Efflorescence is the process in which water molecules in a hydrated or water-containing crystal are lost to the atmosphere. The water is initially contained in the crystal structure of the salt, but when the salt is exposed to air, the water evaporates, leaving behind a powdery residue on the surface of the crystal. This is different from effervescence, which is the escape of gas from an aqueous solution, and phosphorescence and fluorescence, which are types of luminescence.</div>", "topic": "CHEMICAL COMBINATION : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}];
